mapper.sql:
SELECT a.ID, a.PARENT_CODE, a.BERTH_CODE, a.BERTH_NAME, a.BERTH_LONG, a.STATUS, a.CARGO_INFO, a.CREATE_BY, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_TIME, a.WORK_AREA_CD, (SELECT MDD.DICT_LABEL FROM M_DICT_DATA MDD WHERE MDD.DICT_TYPE = 'WORK_AREA' AND MDD.STATUS = '1' AND MDD.DICT_VALUE = a.WORK_AREA_CD) as WORK_AREA_CD_NAME, (select count(*) from M_BERTH_BOLLARD where BERTH_ID = a.ID) AS child_count, (select BERTH_NAME from M_BERTH where BERTH_CODE = a.PARENT_CODE) as PARENT_NAME FROM M_BERTH a
and a.ID = #{id}
and a.PARENT_CODE = #{parentCode}
and a.BERTH_CODE LIKE #{berthCode}
and a.BERTH_NAME LIKE #{berthName}
and a.BERTH_LONG = #{berthLong}
and a.STATUS = #{status}
and a.CARGO_INFO = #{cargoInfo}
ORDER BY BERTH_CODE ASC

mapper.select:
select count(*)
from M_BERTH_BOLLARD
where BERTH_ID = #{id}
